const input = $json;

/* ========== Helpers ========== */
const ensure = v => (v === null || v === undefined) ? '' : String(v);
const stripHtml = s => (s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const truncate = (s, n) => (s && s.length > n ? s.slice(0, n - 1).trim() + '…' : s);

/* ========== Load & Basic Clean ========== */
let html = ensure(input.html || input.textAsHtml || '');
let text = ensure(input.text || stripHtml(html));

html = html
  .replace(/-{2,}\s*Forwarded message\s*-{2,}[\s\S]*?(From:|To:|Date:|Subject:)/gi, '')
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<img[^>]*(tracking|pixel|spacer|tracker)[^>]*>/gi, '')
  .replace(/<(p|div|span|br|strong|em)>\s*<\/\1>/gi, '')
  .replace(/(<br\s*\/?>\s*){2,}/gi, '\n\n');

if (!text || text.length < 10) text = stripHtml(html);

/* ========== Signature & Footer Removal ========== */
const footerMarkers = [
  /p:\s*\d{4}\s*\d{3}\s*\d{4}/i,
  /a:\s*1 Balloon Street, Manchester/i,
  /e:\s*hello@adrankone\.com/i,
  /w:\s*adrankone\.com/i,
  /Registered in England and Wales/i,
  /This e-?mail is confidential/i,
  /Any views or opinions expressed/i,
  /Vat Reg\. No\./i,
  /Company Reg\. No\./i
];
const signatureBlockPattern = /(\s*p:\s*\d{4}\s*\d{3}\s*\d{4}[\s\S]*?adrankone\.com\s*)/gi;

function stripFooter(str) {
  let cleanStr = str.replace(signatureBlockPattern, '').trim();
  let idx = -1;
  footerMarkers.forEach(rx => {
    const m = cleanStr.search(rx);
    if (m >= 0 && (idx === -1 || m < idx)) idx = m;
  });
  return idx >= 0 ? cleanStr.slice(0, idx).trim() : cleanStr;
}

html = stripFooter(html);
text = stripFooter(text);

/* ========== Title / Meta (USE EMAIL SUBJECT ONLY) ========== */
const subjectRaw = ensure(input.subject || input.Subject || '');
const title = subjectRaw || 'Untitled';

const slug = title.toLowerCase()
  .replace(/<[^>]+>/g, '')
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');

const metaTitle = `${truncate(title, 70)} | FTUK`;
const metaDescription = truncate(stripHtml(text || html), 155);

/* ========== Strip existing anchors ========== */
function stripExistingAnchors(txt) {
  return txt.replace(/<a\b[^>]*>/gi, '').replace(/<\/a>/gi, '');
}

/* ========== Normalize <URL> forms ========== */
function normalizeAngleBracketUrls(txt) {
  return txt.replace(/<((?:https?:\/\/|www\.)[^>\s]+)>/gi, '$1');
}

/* ========== Bullet segmentation ========== */
function splitBlocks(raw) {
  return raw.split(/\n{2,}/).map(s => s.trim()).filter(Boolean);
}
let blocks = splitBlocks(text);

/* ====== Remove standalone dashes ====== */
blocks = blocks.map(b => {
  return b
    .split('\n')
    .filter(line => !/^[-\s]*$/.test(line)) // remove lines that are only '-' or whitespace
    .join('\n');
});

/* ========== Subheading detection ========== */
function isSubheading(block) {
  const trimmed = block.trim();
  if (trimmed === title) return false;
  if (/:$/.test(trimmed)) return true;
  const words = trimmed.split(/\s+/);
  if (trimmed.length < 60 && /^[A-Z0-9\s\-\(\)']+$/.test(trimmed) && words.length < 7) return true;
  if (/^[A-Z][a-z]/.test(trimmed) && words.length <= 7 && /:/.test(trimmed)) return true;
  return false;
}

/* ========== Bullet normalization ========== */
function expandBullets(block) {
  const lines = block.split('\n');
  let out = [];
  lines.forEach(line => {
    let l = line.trim();
    if (/^([-\*\.\u2022])\s+/.test(l) || /^\d+\.\s+/.test(l)) {
      l = l.replace(/^([-\*\.\u2022]|\d+\.)\s+/, '');
      out.push('- ' + l);
    } else {
      out.push(l);
    }
  });
  return out.join('\n');
}

/* ========== URL Embedding (same as before) ========== */
const STOP_WORDS = new Set(['the', 'a', 'an', 'this', 'that', 'your', 'our', 'their', 'his', 'her', 'its', 'some', 'any']);

function embedPhraseUrls(textContent) {
  let txt = stripExistingAnchors(textContent);
  txt = normalizeAngleBracketUrls(txt);
  const urlRegex = /(?:https?:\/\/|www\.)[^\s<>"')\],]+/gi;
  let result = '';
  let lastIndex = 0;
  let match;

  while ((match = urlRegex.exec(txt)) !== null) {
    const url = match[0];
    const start = match.index;
    const end = start + url.length;
    const pre = txt.slice(lastIndex, start);
    const phraseCandidate = findPhraseCandidate(pre);
    const anchorText = phraseCandidate ? phraseCandidate.text : null;
    let preSegment = pre;
    if (anchorText) preSegment = pre.slice(0, phraseCandidate.startRel);
    let href = url;
    if (/^www\./i.test(href)) href = 'https://' + href;
    const display = url.length > 60 ? url.slice(0, 57) + '…' : url;
    const anchor = `<a href="${href}" target="_blank" rel="noopener noreferrer">${anchorText || display}</a>`;
    result += preSegment + anchor;
    lastIndex = end;
  }
  result += txt.slice(lastIndex);
  return result;
}

function findPhraseCandidate(preText) {
  const scopeStart = Math.max(0, preText.length - 160);
  const scope = preText.slice(scopeStart);
  let tokens = [];
  let m;
  const wordRegex = /[A-Za-z0-9]+(?:-[A-Za-z0-9]+)*/g;
  while ((m = wordRegex.exec(scope)) !== null) {
    tokens.push({ word: m[0], start: m.index, end: m.index + m[0].length });
  }
  if (!tokens.length) return null;
  const usable = tokens.slice(-3);
  const phraseText = usable.map(t => t.word).join(' ');
  if (phraseText.replace(/[\W_]/g, '').length < 3) return null;
  return { text: phraseText, startRel: usable[0].start };
}

/* ========== Build HTML Content ========== */
const h1Style = "font-size:2.2rem;font-weight:700;margin-bottom:1.1rem;line-height:1.25;";
const h2Style = "font-size:1.3rem;font-weight:700;margin-top:1.35rem;margin-bottom:0.7rem;line-height:1.33;";
const pStyle = "font-size:1.08rem;line-height:1.5;margin-bottom:1.18rem;font-weight:400;";

let contentHtml = `<h1 style="${h1Style}"><strong>${title}</strong></h1>\n\n`;

blocks.forEach(block => {
  let b = block
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/<strong>(.*?)<\/strong>/gi, '$1')
    .replace(/<b>(.*?)<\/b>/gi, '$1')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/<i>(.*?)<\/i>/gi, '<em>$1</em>');
  b = b.replace(/([^\n])\n([^\n])/g, '$1 $2');
  b = expandBullets(b);
  b = embedPhraseUrls(b);

  if (/\n?- /.test(b) && b.split('\n').some(l => l.trim().startsWith('- '))) {
    b.split('\n').forEach(line => {
      const trimmed = line.trim();
      if (trimmed) contentHtml += `<p style="${pStyle}">${trimmed}</p>\n`;
    });
  } else if (isSubheading(b)) {
    const head = b.replace(/:$/, '').trim();
    contentHtml += `<h2 style="${h2Style}"><strong>${head}</strong></h2>\n`;
  } else if (b !== title) {
    contentHtml += `<p style="${pStyle}">${b.trim()}</p>\n`;
  }
});

contentHtml = contentHtml.replace(/\n{3,}/g, '\n\n').trim();

/* ========== Yoast JSON ========== */
const yoast_head_json = {
  title,
  description: metaDescription
};

/* ========== Return ========== */
return {
  json: {
    slug,
    title,
    description: metaDescription,
    content: contentHtml,
    yoast_head_json,
    meta_title: metaTitle,
    meta_description: metaDescription
  }
};

// n8n Code Node: Robust JSON extraction + repair + Trello formatting

const inputItem = $input.first().json;

// Expect message.content
if (!inputItem.message || typeof inputItem.message.content !== "string") {
  return [{ json: { error: "Input structure error: Expected 'message.content' string field." } }];
}

const escapedContentString = inputItem.message.content;

// ------------------------------
// 1) Extract JSON block robustly
// ------------------------------
function extractJsonBlock(text) {
  // Prefer ```json ... ``` but tolerate spacing/case and missing newline after json
  const fenceMatch = text.match(/```json\s*([\s\S]*?)\s*```/i);
  if (fenceMatch && fenceMatch[1]) return fenceMatch[1].trim();

  // Fallback: try to locate an object that contains "social_media_content"
  const idx = text.indexOf('"social_media_content"');
  if (idx !== -1) {
    // Find nearest "{" before it and attempt to slice a full JSON object by brace matching
    const start = text.lastIndexOf("{", idx);
    if (start !== -1) {
      let depth = 0;
      for (let i = start; i < text.length; i++) {
        const ch = text[i];
        if (ch === "{") depth++;
        else if (ch === "}") {
          depth--;
          if (depth === 0) return text.slice(start, i + 1).trim();
        }
      }
    }
  }

  return null;
}

// -----------------------------------------------------
// 2) Repair invalid JSON (control chars inside strings)
// -----------------------------------------------------
function escapeControlCharsInsideStrings(jsonText) {
  // Walk char-by-char; when inside a "..." string, escape raw newlines/tabs/carriage returns
  let out = "";
  let inString = false;
  let escaped = false;

  for (let i = 0; i < jsonText.length; i++) {
    const ch = jsonText[i];

    if (!inString) {
      if (ch === '"') inString = true;
      out += ch;
      continue;
    }

    // inString === true
    if (escaped) {
      out += ch;
      escaped = false;
      continue;
    }

    if (ch === "\\") {
      out += ch;
      escaped = true;
      continue;
    }

    if (ch === '"') {
      out += ch;
      inString = false;
      continue;
    }

    // The killers:
    if (ch === "\n") { out += "\\n"; continue; }
    if (ch === "\r") { out += "\\r"; continue; }
    if (ch === "\t") { out += "\\t"; continue; }

    // Other control chars (0x00-0x1F) inside strings: escape as \u00XX
    const code = ch.charCodeAt(0);
    if (code >= 0x00 && code <= 0x1F) {
      out += "\\u" + code.toString(16).padStart(4, "0");
      continue;
    }

    out += ch;
  }

  return out;
}

function removeTrailingCommas(jsonText) {
  // Remove trailing commas before } or ]
  return jsonText.replace(/,\s*([}\]])/g, "$1");
}

function safeParseJson(jsonText) {
  // Try raw parse
  try {
    return { ok: true, value: JSON.parse(jsonText) };
  } catch (e1) {
    // Repair #1: escape control chars in strings
    const repaired1 = escapeControlCharsInsideStrings(jsonText);
    try {
      return { ok: true, value: JSON.parse(repaired1) };
    } catch (e2) {
      // Repair #2: also remove trailing commas
      const repaired2 = removeTrailingCommas(repaired1);
      try {
        return { ok: true, value: JSON.parse(repaired2) };
      } catch (e3) {
        return {
          ok: false,
          error: "Failed to parse JSON after repairs.",
          details: {
            raw_error: e1.message,
            after_controlchar_repair: e2.message,
            after_trailingcomma_repair: e3.message,
          },
          // Helpful debug (small slice only, so you can inspect without dumping massive content)
          debug_snippet: jsonText.slice(Math.max(0, e1.position - 120), Math.min(jsonText.length, e1.position + 120)),
        };
      }
    }
  }
}

// -----------------------
// 3) Parse nested JSON
// -----------------------
const jsonBlock = extractJsonBlock(escapedContentString);

if (!jsonBlock) {
  return [{ json: { error: "Could not find a JSON block (```json ... ```) or a JSON object containing social_media_content." } }];
}

const parsed = safeParseJson(jsonBlock);

if (!parsed.ok) {
  return [{ json: { error: parsed.error, details: parsed.details, debug_snippet: parsed.debug_snippet } }];
}

const parsedContentObject = parsed.value;

if (!parsedContentObject || !Array.isArray(parsedContentObject.social_media_content)) {
  return [{
    json: {
      error: "Parsed JSON is valid, but missing expected array: social_media_content",
      keys_found: parsedContentObject ? Object.keys(parsedContentObject) : null,
    }
  }];
}

const socialMediaContentArray = parsedContentObject.social_media_content;

// -----------------------------------------
// 4) Your Trello formatting function (kept)
// -----------------------------------------
function toTrelloFormat(content, platform) {
  let output = String(content ?? "")
    .replace(/\\n/g, "\n")
    .replace(/\\"/g, '"')
    .trim();

  const getField = (key) => {
    const match = output.match(new RegExp(`\\*${key}:\\*\\s*(.*?)(?=\\n\\*|$)`, "s"));
    return match ? match[1].trim() : "";
  };

  if (platform.includes("X") || platform.includes("LinkedIn")) {
    const hook = getField("Hook");
    const body = getField("Body");
    const cta = getField("CTA");
    const hashtags = getField("Hashtags");
    const visual = getField("Visual Suggestion");

    output = `*Platform:* ${platform}\n\n`;
    output += `*${hook}*\n\n`;
    output += `${body}\n\n`;
    output += `*Action:* ${cta}\n`;
    output += `*Visual:* ${visual}\n`;
    output += `*Tags:* ${hashtags}`;

  } else if (platform.includes("Carousel")) {
    const theme = getField("Theme");
    const visualStyle = getField("Visual Style");

    output = `# Carousel Theme: *${theme}*\n`;
    output += `*Visual Style:* ${visualStyle}\n\n`;

    const slideStart = String(content).indexOf("### Slide 1 - Title");
    if (slideStart !== -1) {
      output += String(content)
        .substring(slideStart)
        .replace(/\\n/g, "\n")
        .replace(/\\"/g, '"');
    }

  } else if (platform.includes("Live Stream")) {
    const title = getField("Title");
    const duration = getField("Duration");
    const synopsis = getField("Synopsis");

    output = `# Live Stream: ${title}\n`;
    output += `*Duration:* ${duration}\n`;
    output += `*Synopsis:* ${synopsis}\n\n`;

    const pointsStart = String(content).indexOf("### Talking Points");
    if (pointsStart !== -1) {
      output += String(content)
        .substring(pointsStart)
        .replace(/\\n/g, "\n")
        .replace(/\\"/g, '"');
    }
  }

  // Final universal cleanup
  output = output
    .replace(/\*(Hook|Body|CTA|Hashtags|Visual Suggestion|Title|Duration|Synopsis|Platform|Context|Question|Options|Follow-up|Script|Concept):/g, "")
    .trim();

  return output;
}

// -----------------------
// 5) Output flat objects
// -----------------------
const finalOutput = [];

for (const contentPiece of socialMediaContentArray) {
  const platform = String(contentPiece.platform ?? "");
  const blogPostId = contentPiece.blog_post_id ?? null;
  const articleUrl = contentPiece.article_url ?? null;

  const trelloContent = toTrelloFormat(contentPiece.content, platform);

  finalOutput.push({
    json: {
      platform_type: platform,
      blog_post_id: blogPostId,
      article_url: articleUrl,
      content_generated: trelloContent,
    },
  });
}

return finalOutput;

// --- Group Instagram Carousel + Short Videos into separate outputs ---

const inputItems = $input.all();

let instagram = [];
let shortVideos = [];

// Go through every input item
for (const item of inputItems) {
  const data = item.json;
  const platform = (data.platform_type || '').toLowerCase();

  if (platform.includes('instagram carousel')) {
    instagram.push(data);
  }

  if (platform.includes('short video')) {
    shortVideos.push(data);
  }
}

// Prepare outputs
const outputs = [];

// Output 1: Instagram Carousel JSON
if (instagram.length > 0) {
  outputs.push({
    json: {
      type: 'Instagram Carousel',
      count: instagram.length,
      posts: instagram
    }
  });
}

// Output 2: All Short Videos combined into a single JSON
if (shortVideos.length > 0) {
  // Combine content_generated of all short videos into one
  const combinedContent = shortVideos.map(v => v.content_generated).join('\n\n');

  outputs.push({
    json: {
      type: 'Short Videos',
      count: shortVideos.length,
      posts: [
        {
          platform_type: 'Short Videos',
          blog_post_id: shortVideos[0].blog_post_id,
          article_url: shortVideos[0].article_url,
          content_generated: combinedContent
        }
      ]
    }
  });
}

// Return both as separate output items
return outputs;

